import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.AV8XgL04.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/installation.md","filePath":"getting-started/installation.md","lastUpdated":1780389314000}'),l={name:"getting-started/installation.md"};function n(o,e,d,p,r,h){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>ilingo is published as six packages. Install only what you need.</p><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ilingo</span></span></code></pre></div><p>The core ships the <code>Ilingo</code> orchestrator, the <code>IStore</code> port, the <code>MemoryStore</code> adapter, the template engine, and the <code>Intl</code> formatter registry.</p><h2 id="file-system-adapter" tabindex="-1">File-system adapter <a class="header-anchor" href="#file-system-adapter" aria-label="Permalink to &quot;File-system adapter&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @ilingo/fs</span></span></code></pre></div><p>Loads <code>&lt;directory&gt;/&lt;locale&gt;/&lt;namespace&gt;.{js,mjs,cjs,ts,mts,json,conf}</code> files lazily on first access. Use it when your translations live on disk instead of inline in code.</p><h2 id="vue-3-plugin" tabindex="-1">Vue 3 plugin <a class="header-anchor" href="#vue-3-plugin" aria-label="Permalink to &quot;Vue 3 plugin&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @ilingo/vue</span></span></code></pre></div><p>Provides an <code>install()</code> function, a <code>&lt;ITranslate&gt;</code> component, and a <code>useTranslation()</code> composable. Declares <code>vue</code> and <code>@vueuse/core</code> as peer dependencies.</p><h2 id="vuelidate-adapter" tabindex="-1">Vuelidate adapter <a class="header-anchor" href="#vuelidate-adapter" aria-label="Permalink to &quot;Vuelidate adapter&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @ilingo/vuelidate</span></span></code></pre></div><p>Ships translations for the built-in Vuelidate validators in EN / DE / FR / ES. Builds on <code>@ilingo/vue</code>.</p><h2 id="validup-adapter" tabindex="-1">Validup adapter <a class="header-anchor" href="#validup-adapter" aria-label="Permalink to &quot;Validup adapter&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @ilingo/validup</span></span></code></pre></div><p>Framework-agnostic bridge from <a href="https://www.npmjs.com/package/validup" target="_blank" rel="noreferrer">validup</a> <code>Issue</code>s to ilingo — built-in EN / DE / FR / ES catalogs and <code>translateIssue</code> / <code>translateIssues</code> / <code>translateIssueGroups</code> helpers. No Vue; runs in Node SSR, edge, and workers. Declares <code>ilingo</code> and <code>validup</code> as peer dependencies.</p><h2 id="validup-vue-plugin" tabindex="-1">Validup Vue plugin <a class="header-anchor" href="#validup-vue-plugin" aria-label="Permalink to &quot;Validup Vue plugin&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @ilingo/validup-vue</span></span></code></pre></div><p>The Vue 3 layer for <code>@ilingo/validup</code>: composables, the <code>&lt;IValidup&gt;</code> / <code>&lt;IValidupT&gt;</code> components, and the install hook. Builds on <code>@ilingo/vue</code>; declares <code>@validup/vue</code> among its peers.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>Node.js 22+</strong> for development. The published bundles run anywhere ES2022 + <code>Intl.PluralRules</code> / <code>Intl.NumberFormat</code> / <code>Intl.DateTimeFormat</code> / <code>Intl.ListFormat</code> are available — which is every modern browser and every supported Node version.</li><li><strong>ESM only.</strong> Every package declares <code>&quot;type&quot;: &quot;module&quot;</code>. CommonJS consumers can use dynamic <code>import()</code>.</li></ul>',22)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
